            const tilt = Math.max(Math.abs(refined.topRight.y - refined.topLeft.y), Math.abs(refined.bottomRight.y - refined.bottomLeft.y), Math.abs(refined.bottomLeft.x - refined.topLeft.x), Math.abs(refined.bottomRight.x - refined.topRight.x)) / Math.max(1, approximateSpan);
